import{formatNumber,formatCurrencyVN}from './admin-utils.js';export async function loadDashboard(){try{if(window.BinhPhapAPI){const stats=await window.BinhPhapAPI.getDashboardStats();updateDashboardStats(stats);return;}if(window.AdminAPI){const stats=await loadDashboardFromAPI();updateDashboardStats(stats);}}catch(error){loadDemoDashboard();}}async function loadDashboardFromAPI(){const [customers,projects,invoices,campaigns]=await Promise.all([ window.AdminAPI.loadCustomers({limit: 0}),window.AdminAPI.loadPosts ? window.AdminAPI.loadPosts({limit: 0}):{data: []},window.AdminAPI.loadCustomers ? window.AdminAPI.loadCustomers({status: 'active'}):{data: []},{data: []}]);return{total_customers: customers.data?.length||0,active_projects: projects.data?.length||0,pending_revenue: invoices.data?.reduce((sum,c)=>sum+(c.value||0),0)||0,active_campaigns: campaigns.data?.length||0};}export function updateDashboardStats(stats){const elCustomers=document.getElementById('stat-customers');if(elCustomers){animateCountUp(elCustomers,stats.total_customers||0);}const elProjects=document.getElementById('stat-projects');if(elProjects){animateCountUp(elProjects,stats.active_projects||0);}const elRevenue=document.getElementById('stat-revenue');if(elRevenue){const value=stats.pending_revenue||0;elRevenue.textContent=formatCurrencyVN(value);}const elCampaigns=document.getElementById('stat-campaigns');if(elCampaigns){animateCountUp(elCampaigns,stats.active_campaigns||0);}}export function loadDemoDashboard(){const demoStats={total_customers: 48,active_projects: 12,pending_revenue: 245000000,active_campaigns: 8};updateDashboardStats(demoStats);}export function animateCountUp(element,targetValue,duration=1500,suffix=''){if(!element)return;const startValue=0;const startTime=performance.now();function update(currentTime){const elapsed=currentTime-startTime;const progress=Math.min(elapsed/duration,1);const easeOut=1-Math.pow(1-progress,3);const currentValue=Math.floor(startValue+(targetValue-startValue)*easeOut);if(typeof targetValue==='number'&&targetValue>=1000000){element.textContent=(currentValue/1000000).toFixed(1)+'M'+suffix;}else if(typeof targetValue==='number'&&targetValue>=1000){element.textContent=(currentValue/1000).toFixed(1)+'K'+suffix;}else{element.textContent=currentValue+suffix;}if(progress<1){requestAnimationFrame(update);}else{element.textContent=formatNumber(targetValue)+suffix;}}requestAnimationFrame(update);}export function createSparkline(data,trend='up'){if(!data||data.length<2)return '';const width=120;const height=40;const padding=4;const maxVal=Math.max(...data);const minVal=Math.min(...data);const range=maxVal-minVal||1;const points=data.map((val,i)=>{const x=padding+(i/(data.length-1))*(width-2*padding);const y=height-padding-((val-minVal)/range)*(height-2*padding);return `${x},${y}`;}).join(' ');const colors={up: '#2E7D32',down: '#C62828',neutral: '#757575'};const color=colors[trend]||colors.neutral;return `<svg width="${width}" height="${height}" viewBox="0 0 ${width}${height}"><polyline points="${points}" fill="none" stroke="${color}" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"/></svg>`;}